// ⬇️ PASTE YOUR NITTER RSS LINK HERE ⬇️
return [
  {
    json: {
      rss_url: 'http://srv-captain--nitter-hidden:8080/search/rss?f=tweets&q=sinaloa&e-quote=on&e-replies=on&e-nativeretweets=on'
    }
  }
];

const item = $input.item.json;
const rawUrl = item.rss_url;

if (!rawUrl) {
  throw new Error("rss_url is missing from input");
}

const cleanUrl = rawUrl.trim();

// 1. Manually Extract Hostname
let host = 'unknown-host';
try {
    const protocolSplit = cleanUrl.split('://');
    const afterProtocol = protocolSplit.length > 1 ? protocolSplit[1] : protocolSplit[0];
    host = afterProtocol.split('/')[0];
} catch (e) {}

// 2. Manually Extract Query Parameters
const params = {};
try {
    const querySplit = cleanUrl.split('?');
    if (querySplit.length > 1) {
        const queryString = querySplit[1];
        const pairs = queryString.split('&');

        pairs.forEach(pair => {
            const parts = pair.split('=');
            if (parts.length >= 2) {
                const key = parts[0];
                const val = decodeURIComponent(parts[1] || ''); 
                params[key] = val;
            }
        });
    }
} catch (e) {}

// 3. Separate 'q' (Query)
const searchQuery = params['q'] || 'Unknown';
if (params['q']) delete params['q'];

return {
  json: {
    full_url: cleanUrl,
    host_name: host,
    search_query: searchQuery,
    filters: JSON.stringify(params)
  }
};

// Get the Raw XML String from the HTTP node
const xml = $input.item.json.data;

if (!xml) {
  throw new Error("No Data returned from HTTP Request");
}

try {
  // Get the Search ID from the DB Registration step
  // Wrapping this in try/catch or optional chaining is recommended in case input is improper
  const searchNode = $('Register Search').first();
  const searchId = searchNode ? searchNode.json.id : null;

  // Helper to extract value between tags
  function getTagValue(text, tagName) {
    // Note: In new RegExp("string"), we DO use double backslashes \\s
    const regex = new RegExp(`<${tagName}[^>]*>([\\s\\S]*?)<\\/${tagName}>`, 'i');
    const match = text.match(regex);
    if (!match) return null;

    let val = match[1];
    // Remove CDATA tags if they exist
    val = val.replace(/<!\[CDATA\[/g, '').replace(/\]\]>/g, '');
    return val.trim();
  }

  const tweets = [];

  // Split the XML by <item> tags to isolate each tweet
  const items = xml.split('<item>');

  // Start at index 1 because index 0 is the RSS header info
  for (let i = 1; i < items.length; i++) {
      // Ensure we stop at </item>
      const itemContent = items[i].split('</item>')[0];

      tweets.push({
          json: {
              search_id: searchId,
              nitter_guid: getTagValue(itemContent, 'guid'),
              // FIX: Use getTagValue with the specific XML namespace tag
              // We check dc:creator first, fall back to author
              author_handle: getTagValue(itemContent, 'dc:creator') || getTagValue(itemContent, 'author'),
              title: getTagValue(itemContent, 'title'),
              content_html: getTagValue(itemContent, 'description'),
              tweet_link: getTagValue(itemContent, 'link'),
              published_at: getTagValue(itemContent, 'pubDate')
          }
      });
  }

  return tweets;
} catch (e) {
  throw new Error("XML Parsing Failed: " + e.message);
}

const inputItem = $input.item;
const errorData = inputItem.error || inputItem.json || {};
let contextUrl = 'Unknown URL';
try {
    contextUrl = $('Configuration (Set URL)').item.json.rss_url;
} catch(e) {}

let errorMessage = 'Unknown error';
let errorDetails = '';

if (errorData.message) {
  errorMessage = errorData.message;
  if (errorData.description) {
      errorDetails = `\n\nDetails: ${errorData.description}`;
  }
} else if (typeof errorData === 'string') {
    errorMessage = errorData;
} else {
    errorMessage = JSON.stringify(errorData);
}

// Helper to escape HTML characters so Telegram doesn't crash
function escapeHtml(unsafe) {
    if (!unsafe) return '';
    return unsafe
         .replace(/&/g, "&amp;")
         .replace(/</g, "&lt;")
         .replace(/>/g, "&gt;");
}

const safeMsg = escapeHtml(errorMessage + errorDetails);
const safeNode = escapeHtml($input.item.triggerNode || 'Unknown');

return {
  json: {
    // We use HTML formatting here. <a href="..."> is supported.
    // <pre> allows us to dump the error message safely without breaking formatting.
    message: `⚠️ <b>Nitter Ingestion Failed</b>\n\n` +
             `<b>Node Failed:</b> ${safeNode}\n` +
             `<b>Target:</b> <a href="${contextUrl}">RSS Feed</a>\n` +
             `<b>Error:</b>\n<pre>${safeMsg}</pre>`
  }
};
